INSERT INTO public.products (name, category, price, stock, tag, description, images, colors) VALUES
  ('Tailored Wool Blazer', 'Clothing', 145000, 12, 'Trending', 'Structured in a refined wool blend, this blazer combines sharp tailoring with a relaxed silhouette. A two-button closure, clean notch lapel, and a lightly padded shoulder create a frame that works from business meetings to elevated evenings.', '["https://images.unsplash.com/photo-1593030103066-0093718efeb9?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1507679799987-c73779587ccf?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1490578474895-699cd4e2cf59?w=600&q=80&auto=format&fit=crop"]', '[{"name":"Charcoal","hex":"#2b2b2b"},{"name":"Camel","hex":"#9c7a4a"},{"name":"Navy","hex":"#1f2a44"},{"name":"Black","hex":"#111111"},{"name":"Grey","hex":"#6b6b6b"}]'),
  ('Slim-Fit Oxford Shirt', 'Clothing', 38000, 25, 'New', 'A wardrobe essential woven in crisp Oxford cloth. The slim cut drapes cleanly through the chest and shoulders, while the classic button-down collar keeps the look polished whether worn tucked or loose.', '["https://images.unsplash.com/photo-1602810318383-e386cc2a3ccf?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1596755094514-f87e34085b2c?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1620799139834-6dc8df5aa9c3?w=600&q=80&auto=format&fit=crop"]', '[{"name":"White","hex":"#f5f3ee"},{"name":"Sky","hex":"#6f8faa"},{"name":"Black","hex":"#111111"},{"name":"Light Pink","hex":"#e3b9bb"},{"name":"Lavender","hex":"#a59cc2"}]'),
  ('Classic Denim Jacket', 'Clothing', 52000, 18, 'Trending', 'Washed to a lived-in perfection, this denim jacket brings effortless structure to any layered look. Chest pockets, a tailored cut, and a clean finish elevate it well above the ordinary.', '["https://images.unsplash.com/photo-1551489186-cf8726f514f8?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1576566588028-4147f3842f27?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1544441892-794166f1e3be?w=600&q=80&auto=format&fit=crop"]', '[{"name":"Indigo","hex":"#33455c"},{"name":"Black","hex":"#111111"},{"name":"Light Wash","hex":"#7d93a8"},{"name":"Grey","hex":"#6b6b6b"}]'),
  ('Linen Resort Shirt', 'Clothing', 34000, 20, NULL, 'Spun from lightweight linen that breathes through warm weather with ease. The relaxed camp collar and subtle natural texture make it the natural choice for summer dressing, on or off the coast.', '["https://images.unsplash.com/photo-1620799140408-edc6dcb6d633?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1591047139829-d91aecb6caea?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1499636136210-6f4ee915583e?w=600&q=80&auto=format&fit=crop"]', '[{"name":"Sand","hex":"#c9b48b"},{"name":"Olive","hex":"#5c5b3f"},{"name":"White","hex":"#f5f3ee"},{"name":"Terracotta","hex":"#a85c41"}]'),
  ('Wool Flannel Trousers', 'Clothing', 46000, 15, NULL, 'Cut from a mid-weight wool flannel that drapes with ease from waistband to break. A slightly tapered leg keeps the silhouette modern without sacrificing the comfort of a fuller cut.', '["https://images.unsplash.com/photo-1473966968600-fa801b869a1a?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1542272604-787c3835535d?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1584865288642-42078afe6942?w=600&q=80&auto=format&fit=crop"]', '[{"name":"Graphite","hex":"#3a3a3a"},{"name":"Navy","hex":"#1f2a44"},{"name":"Black","hex":"#111111"},{"name":"Camel","hex":"#9c7a4a"}]'),
  ('Chukka Leather Boots', 'Shoes', 95000, 10, 'Trending', 'Handcrafted from full-grain leather with a cushioned crepe-effect sole for quiet, refined wear. The ankle-height silhouette transitions effortlessly from formal to casual settings.', '["https://images.unsplash.com/photo-1638247025967-b4e38f787b76?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1542291026-7eec264c27ff?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1520219306100-ec4afbdb4e8f?w=600&q=80&auto=format&fit=crop"]', '[{"name":"Cognac","hex":"#8a4b2b"},{"name":"Black","hex":"#111111"},{"name":"Dark Brown","hex":"#4a3322"}]'),
  ('Classic Derby Shoes', 'Shoes', 88000, 14, NULL, 'A foundational piece in any considered wardrobe. Cut from smooth leather with open lacing and a leather sole, they reward years of wear with a deep, character-rich patina.', '["https://images.unsplash.com/photo-1614252369475-531eba835eb1?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1583209814683-c81ed7eb8f00?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1533867617858-e7b97e060509?w=600&q=80&auto=format&fit=crop"]', '[{"name":"Black","hex":"#111111"},{"name":"Brown","hex":"#5b3a24"},{"name":"Burgundy","hex":"#5c2027"}]'),
  ('Canvas Low-Top Sneakers', 'Shoes', 42000, 30, 'New', 'Built on a clean vulcanised sole with a sturdy canvas upper. Minimal by design and comfortable by nature — the versatile everyday choice that pairs with almost anything.', '["https://images.unsplash.com/photo-1549298916-b41d501d3772?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1600269452121-4f2416e55c28?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1595950653106-6c9ebd614d3a?w=600&q=80&auto=format&fit=crop"]', '[{"name":"White","hex":"#f2f2f2"},{"name":"Black","hex":"#111111"},{"name":"Grey","hex":"#8a8a8a"},{"name":"Navy","hex":"#1f2a44"}]'),
  ('Full-Grain Leather Belt', 'Accessories', 22000, 40, NULL, 'Cut from a single strip of full-grain leather and finished with a solid-brass buckle. The width and weight are calibrated to work equally well with dress trousers and denim.', '["https://images.unsplash.com/photo-1624222247344-550fb60583dc?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1611816001670-0cde22d7f7b2?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1617196034096-1d90b6c91584?w=600&q=80&auto=format&fit=crop"]', '[{"name":"Black","hex":"#111111"},{"name":"Brown","hex":"#5b3a24"},{"name":"Tan","hex":"#b08c5f"}]'),
  ('Aviator Sunglasses', 'Accessories', 28000, 22, 'Trending', 'Precision-formed wire frames with teardrop lenses and full UV protection. A timeless shape that flatters a broad range of face structures and never looks out of place.', '["https://images.unsplash.com/photo-1473496169904-658ba7c44d8a?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1572635196237-14b3f281503f?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1511499767150-a48a237f0083?w=600&q=80&auto=format&fit=crop"]', '[{"name":"Gold","hex":"#D4AF37"},{"name":"Black","hex":"#111111"},{"name":"Tortoise","hex":"#6b4a2a"},{"name":"Silver","hex":"#b9bdc1"}]'),
  ('Automatic Chrono Watch', 'Accessories', 135000, 6, 'New', 'A Swiss-inspired automatic movement visible through an exhibition caseback. Three sub-dials track elapsed hours, minutes, and seconds — a mechanical statement worn on the wrist.', '["https://images.unsplash.com/photo-1524592094714-0f0654e20314?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1508685096489-7aacd43bd3b1?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1523275335684-37898b6baf30?w=600&q=80&auto=format&fit=crop"]', '[{"name":"Gold","hex":"#D4AF37"},{"name":"Steel","hex":"#9aa0a6"},{"name":"Black","hex":"#111111"},{"name":"Rose Gold","hex":"#b76e64"}]'),
  ('Merino Wool Beanie', 'Accessories', 15000, 35, NULL, 'Knitted from extra-fine merino fibre for warmth without weight or itch. A rib-knit cuff and close-fitting shape keep it sleek under any collar — elegant even when it''s cold.', '["https://images.unsplash.com/photo-1576871337622-98d48d1cf531?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1510590337257-9bff36b8d51c?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1603252109360-909baaf261ae?w=600&q=80&auto=format&fit=crop"]', '[{"name":"Charcoal","hex":"#2b2b2b"},{"name":"Camel","hex":"#9c7a4a"},{"name":"Black","hex":"#111111"},{"name":"Burgundy","hex":"#5c2027"}]'),
  ('Brunchelo', 'Shoes', 15000, 8, NULL, 'A contemporary silhouette crafted for all-day comfort without compromising style. Lightweight construction and a refined profile make it a natural companion from morning to evening.', '["/Products/Shoes/Brunchelo.jfif","/Products/Shoes/shoe.jfif","/Products/Shoes/sample.jfif"]', '[{"name":"Charcoal","hex":"#2b2b2b"},{"name":"Dark green","hex":"#055c18"},{"name":"Black","hex":"#111111"},{"name":"Burgundy","hex":"#5c2027"}]'),
  ('Loro Piana Summer Walk', 'Shoes', 15000, 7, NULL, 'Inspired by the iconic Loro Piana tradition of luxury comfort, this sneaker pairs sumptuous materials with an understated silhouette — the very definition of quiet luxury done right.', '["/Products/Shoes/Loro piana summer walk.jfif","/Products/Shoes/Loro piana shoe.jfif","/Products/Shoes/summer walk collection.jfif"]', '[{"name":"Charcoal","hex":"#2b2b2b"},{"name":"Camel","hex":"#9c7a4a"},{"name":"Black","hex":"#111111"},{"name":"White","hex":"#f3eeef"}]'),
  ('Cashmere Crewneck Sweater', 'Clothing', 78000, 16, 'New', 'Woven from Grade-A cashmere for exceptional softness and lasting warmth. The classic crewneck silhouette and ribbed trim make it a perennial staple across seasons and occasions.', '["https://images.unsplash.com/photo-1620799139507-2a76f79a2f4d?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1614676471928-2ed0ad1061a4?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1523381210434-271e8be1f52b?w=600&q=80&auto=format&fit=crop"]', '[{"name":"Camel","hex":"#9c7a4a"},{"name":"Ivory","hex":"#f0ece0"},{"name":"Navy","hex":"#1f2a44"},{"name":"Charcoal","hex":"#2b2b2b"}]'),
  ('Pleated Chino Trousers', 'Clothing', 41000, 19, NULL, 'A softer alternative to formal tailoring. Front pleats offer room to move while a clean line from hip to ankle maintains a polished, put-together appearance all day long.', '["https://images.unsplash.com/photo-1624378439575-d8705ad7ae80?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1604176354204-9268737828e4?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1542272604-787c3835535d?w=600&q=80&auto=format&fit=crop"]', '[{"name":"Khaki","hex":"#c2a97e"},{"name":"Navy","hex":"#1f2a44"},{"name":"Olive","hex":"#5c5b3f"},{"name":"Black","hex":"#111111"}]'),
  ('Suede Loafers', 'Shoes', 72000, 11, 'Trending', 'Slip-on ease meets Goodyear-welt construction. The nubuck suede upper molds gently to the foot over time, developing a character and fit that is entirely your own.', '["https://images.unsplash.com/photo-1603808033192-082d6919d3e1?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1567401893414-76b7b1e5a7a5?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1582897085656-c636d006a246?w=600&q=80&auto=format&fit=crop"]', '[{"name":"Tan","hex":"#b08c5f"},{"name":"Navy","hex":"#1f2a44"},{"name":"Burgundy","hex":"#5c2027"},{"name":"Black","hex":"#111111"}]'),
  ('Leather Tote Bag', 'Accessories', 55000, 9, 'New', 'Structured in vegetable-tanned leather that softens and patinas beautifully with age. A spacious interior holds daily essentials with room to spare; twin handles allow shoulder or hand carry.', '["https://images.unsplash.com/photo-1548036328-c9fa89d128fa?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1591488320449-011701bb6704?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1594938298603-c8148c4b4057?w=600&q=80&auto=format&fit=crop"]', '[{"name":"Tan","hex":"#b08c5f"},{"name":"Black","hex":"#111111"},{"name":"Brown","hex":"#5b3a24"}]'),
  ('Polo Shirt', 'Clothing', 32000, 28, NULL, 'The quintessential refined casual — a rib-knit collar, a two-button placket, and short sleeves cut to sit cleanly on the shoulder. Comfortable enough for leisure, sharp enough for smart-casual settings.', '["https://images.unsplash.com/photo-1586790170083-2f9ceadc732d?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1598300042247-d088f8ab3a91?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1571945153237-4929e783af4a?w=600&q=80&auto=format&fit=crop"]', '[{"name":"White","hex":"#f5f3ee"},{"name":"Navy","hex":"#1f2a44"},{"name":"Black","hex":"#111111"},{"name":"Burgundy","hex":"#5c2027"},{"name":"Olive","hex":"#5c5b3f"}]'),
  ('Running Sneakers', 'Shoes', 65000, 17, 'Trending', 'Engineered for performance with a cushioned midsole and a breathable mesh upper. Reflective accents and a flexible outsole make them equally at home on the track or the street.', '["https://images.unsplash.com/photo-1542291026-7eec264c27ff?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1606107557195-0e29a4b5b4aa?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1608231387042-66d1773070a5?w=600&q=80&auto=format&fit=crop"]', '[{"name":"White","hex":"#f2f2f2"},{"name":"Black","hex":"#111111"},{"name":"Grey","hex":"#8a8a8a"}]'),
  ('Silk Pocket Square', 'Accessories', 12000, 50, NULL, 'Cut from 100% silk and hand-rolled at the edges. A single square introduces texture and colour to any breast pocket without overpowering the suit it accompanies.', '["https://images.unsplash.com/photo-1618517351616-38fb9c5210c6?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1607345366928-199ea26cfe3e?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1598208627373-1a2df672a16c?w=600&q=80&auto=format&fit=crop"]', '[{"name":"Gold","hex":"#D4AF37"},{"name":"Navy","hex":"#1f2a44"},{"name":"Burgundy","hex":"#5c2027"},{"name":"White","hex":"#f5f3ee"}]'),
  ('Quilted Bomber Jacket', 'Clothing', 89000, 13, 'Trending', 'Insulated with a lightweight quilted fill and finished in a clean matte shell. Ribbed cuffs and waistband seal in warmth while the minimal body keeps the silhouette sharp and modern.', '["https://images.unsplash.com/photo-1551028719-00167b16eac5?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1520975954732-35dd22299614?w=600&q=80&auto=format&fit=crop","https://images.unsplash.com/photo-1591047139829-d91aecb6caea?w=600&q=80&auto=format&fit=crop"]', '[{"name":"Black","hex":"#111111"},{"name":"Olive","hex":"#5c5b3f"},{"name":"Navy","hex":"#1f2a44"},{"name":"Camel","hex":"#9c7a4a"}]'),
